import{_ as p}from"./plugin-vue_export-helper-c27b6911.js";import{o as e,c as _,f as t}from"./app-4ea9d5e7.js";const a={},c=t('<h1 id="_21-引擎层和编排层" tabindex="-1"><a class="header-anchor" href="#_21-引擎层和编排层" aria-hidden="true">#</a> #21 引擎层和编排层</h1><p>这是我2026年最重要的文章。</p><p>有了这种看待问题的新视野，未来我构建的机制会长盛不衰，又能适应变化。基于这种思路，我会赚取到比当前大得多的财富。</p><hr><p>频繁变化和内核稳定，一直是两个互斥的话题。</p><p>写代码的人经常有这种感觉，如果你已经写完了某一套代码。这时候需求变化，这时候你想改内核往往已经来不及了，只能通过加if-else，或者是对于返回的结果，再包装一层加一点东西的方式。缝补上去。</p><p>如果这个时候，需求继续变化呢？又还要继续缝补。随着需求继续变化，最后甚至会出现缝补的部分，比原来的部分还有大的情况。这种在现实世界屡见不鲜。</p><p>大模型时代提供了一个新思路。（其实是一个早就有的思路，只是这种方法论现在更被世人所知）</p><p>将你的内容拆分成为引擎层和编排层。</p><p>例如Mysql是存储的引擎层，所有存储的能力都用Mysql去做。上层可以随意你怎么进行编排。建什么库，都随意。</p><p>大模型底层的入参是提示词，输出是提示词的内容。核心能力很一致。速度，效率，大模型的智商这些都很重要。然后这个再通过编排层组织起来。</p><p>编排层解决什么问题，解决这个世界多种多样的问题。你写代码，我写文章，我做ppt，大家需要的是不同的编排层。你想要实现的持续运行，高质量等等等。都通过编排层去实现。</p><p>引擎层提供核心能力。编排层负责适配多种多样的业务。</p><p>只要保持引擎层稳定，你就一定可以知道，出不了什么c岔子。核心的计算都在引擎层做了。</p><p>Claude Code就是当前AI编码方便最专业的编排工具。未来一定还会有其他各种编排工具。</p><p>从公司的视角来想一下这个问题，其实每一个员工也是提供核心能力的Agent。一个良好的组织架构，或者是Harnes工程引导（例如职责，绩效引导等）也是一种编排。</p><p>引擎层其实就是那几个，但是编排层，是可以做到非常多的。适配于不同的业务，你发现你做实验的速度一旦有点慢了，就一定说明你的编排层一定有不适配于实际需要的地方了。</p><p>量化的计算引擎和，编排层此处体现得非常明显。引擎层负责规定具体计算，编排层可以做Batch或者其他。编排层才可以持续的利用CPU让计算持续不断。</p><p>以后做任何事情，都要想这个问题拆引擎层和编排层了没有？是哪一层需要优化。例如未来开AI自媒体的公司，生产内容的引擎层准备好了。以及上层的编排层，是否也好了呢？</p><p>这种模式下，迭代速度回非常之快。稳定度会非常之高。</p>',20),r=[c];function o(s,n){return e(),_("div",null,r)}const l=p(a,[["render",o],["__file","21 引擎层和编排层.html.vue"]]);export{l as default};
